  ('heelevel3-53250add-moex-00112', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '有關行政法院之管轄，下列敘述何者正確？', '["於高等行政法院增設地方行政訴訟庭，專責部分之第一審通常訴訟程序事件、簡易訴訟程序、 交通裁決、收容聲請等事件", "當事人不服由高等行政法院地方行政訴訟庭所作成之判決，而提出上訴由最高行政法院管轄", "以高等行政法院地方行政訴訟庭為第一審管轄法院之事件，高等行政法院高等行政訴訟庭依通 常訴訟程序審理並為判決者，最高行政法院應以高等行政法院高等行政訴訟庭無管轄權而廢棄 原判決", "聲請人、受裁定人或內政部移民署對高等行政法院地方行政訴訟庭所為收容聲請事件之裁定不 服者，應向最高行政法院為抗告"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00113', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '下列何者屬於行政秩序罰？', '["工廠負責人不遵行主管機關依法所為之停工命令，被判處有期徒刑併科罰金", "人民不履行行政法上之義務，遭行政機關科處怠金", "律師違反律師法規定而受懲戒", "電信事業未經核准擅自架設電臺，依法沒入電臺之設備或器材"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00114', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '關於國家賠償之敘述，下列何者正確？', '["公共設施因設置或管理有欠缺，致人民受損害，如有其他應負責之人，國家不負賠償責任", "於開放之自然公物，經管理機關已就使用該公物為適當之警告，而人民仍從事冒險或具危險性 活動，國家不負損害賠償責任", "國家因採購公務所需之文具造成之損害，亦屬國家賠償責任", "有審判職務之公務員，因執行職務侵害人民自由或權利，就其參與審判或追訴案件犯職務上之 罪，經第一審判決有罪，負國家賠償責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00115', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '人民因正當使用合法藥物所生之藥害，得依藥害救濟法請求救濟，此之所謂「救濟」，其法律上定 性為何？', '["民事損害賠償", "國家賠償", "刑事訴訟附帶民事賠償", "基於社會衡平所為之行政補償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00116', 'heelevel3-53250add', 'heelevel3-53250add-moex-112-cd0ce497', 'sub-heelevel3-53250add-04', NULL, 'essay', '商標法第6條第1項規定：「申請商標註冊及其相關事務，得委任商標代理
人辦理之。但在中華民國境內無住所或營業所者，應委任商標代理人辦理
之」，專利法第11條也有類似的規定。請詳述此類規定是否對外國申請人
課以較本國人為高之要求而違反與貿易有關智慧財產權協定（TRIPS協
定）之國民待遇原則？（30分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "12c8a7b4f7a1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "336", "s": "1221", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "世界貿易組織法規(與貿易有關之智慧財產協定)", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00117', 'heelevel3-53250add', 'heelevel3-53250add-moex-112-cd0ce497', 'sub-heelevel3-53250add-04', NULL, 'essay', '與貿易有關智慧財產權協定（TRIPS協定）第二篇規範WTO會員有關於智
慧財產權的有效性、範圍及使用之標準。其中除規定最低保護標準外，也
明定允許會員在一定情況下對於相同之智慧財產權可以有不同的保護標
準或途徑。例如TRIPS第25條第1項即規定：「會員應對獨創之工業設計具
新穎性或原創性者，規定予以保護…會員得規定，此種保護不及於主要基
於技術或功能性之設計」。請另舉三例TRIPS協定第二篇中相類似明文以
「應…」及「得…」方式呈現之規定。亦請逐例敘述並比較我國相對應之
智慧財產權規範或保護方法。（30分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "12c8a7b4f7a1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "336", "s": "1221", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "世界貿易組織法規(與貿易有關之智慧財產協定)", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00118', 'heelevel3-53250add', 'heelevel3-53250add-moex-112-cd0ce497', 'sub-heelevel3-53250add-04', NULL, 'essay', '與貿易有關智慧財產權協定（TRIPS協定）第三篇第四節規範與邊界措施
